1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
14	const CURSE_SURCHARGE_RATE = 0.5;
15	type Step = { op: "quote"; items: Item[] };
16	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
17	
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PRICE = 60;
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const countByType = (items: Item[]): Record<string, number> => {
23	  const counts: Record<string, number> = {};
24	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
25	  return counts;
26	};
27	
28	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
29	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
30	
31	const lineItemPrice = (type: string, count: number): number =>
32	  qualifiesForComponentBlock(type, count)
33	    ? COMPONENT_BLOCK_PRICE
34	    : BASE_PREMIUM[type] * count;
35	
36	const sumBasePremiums = (items: Item[]): number =>
37	  Object.entries(countByType(items))
38	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
39	
40	const itemSurcharges = (items: Item[]): number =>
41	  items.reduce((sum, item) => {
42	    const base = BASE_PREMIUM[item.type];
43	    return sum + (item.cursed ? base * CURSE_SURCHARGE_RATE : 0);
44	  }, 0);
45	
46	const quotePremium = (items: Item[]): number => {
47	  const basePremium = sumBasePremiums(items);
48	  const surcharges = itemSurcharges(items);
49	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
50	  return Math.ceil(basePremium + surcharges + firstInsurance + PROCESSING_FEE);
51	};
52	
53	export const runScenario = (input: unknown): unknown => {
54	  const scenario = input as Scenario;
55	  const results = scenario.steps.map(({ items }) => ({ premium: quotePremium(items) }));
56	  return { results };
57	};
